components.codeTemplate:
Canvas(opaque: {opaque}, colorMode: .{colorMode}, rendersAsynchronously: {rendersAsynchronously}) { context, size in
    context.blendMode = .{blendMode}
    let path = Path(ellipseIn: CGRect(origin: .zero, size: size))
    context.stroke(path, with: .color({strokeColor}), lineWidth: {lineWidth})
}
.frame(height: {canvasHeight})

VideoPlayer(player: player) {
    if {showsOverlay} {
        Text("{overlayText}")
            .font(.caption).bold()
            .padding(6)
            .background(.red, in: Capsule())
            .padding()
            .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .topLeading)
    }
}
.frame(width: {width}, height: {height})
.clipShape(RoundedRectangle(cornerRadius: {cornerRadius}, style: .continuous))
.accessibilityLabel("{accessibilityLabel}")
.task {
    let p = AVPlayer(url: URL(string: "{urlString}")!)
    if {autoplay} { p.play() }
    player = p
}
